// cdp_notifier — parse receiver handoff webhook and prepare pipeline-result API call.

function env(name) {
  try {
    if (typeof $env !== 'undefined' && $env && $env[name]) {
      return String($env[name]).trim();
    }
  } catch (e) {}
  try {
    if (typeof process !== 'undefined' && process.env && process.env[name]) {
      return String(process.env[name]).trim();
    }
  } catch (e) {}
  return '';
}

function workflowName() {
  try {
    if (typeof $workflow !== 'undefined' && $workflow && $workflow.name) {
      return String($workflow.name).trim();
    }
  } catch (e) {}
  return '';
}

function isDevWorkflow() {
  return /^DEV\s*-/i.test(workflowName());
}

function devEnvName(name) {
  return {
    CDP_SCRAPER_API_BASE: 'CDP_DEV_SCRAPER_API_BASE',
    MUVSTOK_SCRAPER_API_BASE: 'CDP_DEV_SCRAPER_API_BASE',
    CDP_API_KEY: 'CDP_DEV_API_KEY',
    MUVSTOK_API_KEY: 'CDP_DEV_API_KEY',
    API_KEY: 'CDP_DEV_API_KEY',
  }[name] || '';
}

function envFor(name) {
  if (!isDevWorkflow()) return env(name);
  const mapped = devEnvName(name);
  return mapped ? env(mapped) : env(name);
}

function trimTrailingSlashes(value) {
  let out = String(value || '').trim();
  while (out.endsWith('/')) out = out.slice(0, -1);
  return out;
}

function parseBody(raw) {
  let p = raw;
  if (typeof p === 'string') {
    try {
      p = JSON.parse(p);
    } catch (e) {
      p = {};
    }
  }
  return p && typeof p === 'object' ? p : {};
}

const wh = $('🔔 Webhook cdp-notifier').first().json;
const body = parseBody(wh.body);
const batchGroupId = String(body.batch_group_id || '').trim();
const source = String(body.source || '').trim().toLowerCase();
const status = String(body.status || 'completed').trim().toLowerCase();
const summary = body.summary && typeof body.summary === 'object' ? body.summary : {};

if (!batchGroupId || (source !== 'scraper' && source !== 'stokapi')) {
  return [{ json: { skip: true, reason: 'invalid_handoff' } }];
}

const apiBase = trimTrailingSlashes(
  envFor('CDP_SCRAPER_API_BASE') || envFor('MUVSTOK_SCRAPER_API_BASE') || ''
);
const apiKey = envFor('CDP_API_KEY') || envFor('MUVSTOK_API_KEY') || envFor('API_KEY');

return [
  {
    json: {
      skip: false,
      pipeline_result_url:
        apiBase + '/api/v1/dispatch-runs/by-batch/' + encodeURIComponent(batchGroupId) + '/pipeline-result',
      pipeline_result_api_key: apiKey,
      pipeline_result_body: {
        source,
        status,
        summary,
      },
      handoff: body,
    },
  },
];

// cdp_notifier - format one final Telegram/email from the aggregate pipeline claim.

const WEBSCRAPERS_LABEL = 'WEBSCRAPERS';
const ESTOQUE_LABEL = 'ESTOQUE ONLINE';

function env(name) {
  try {
    if (typeof $env !== 'undefined' && $env && $env[name]) {
      return String($env[name]).trim();
    }
  } catch (e) {}
  try {
    if (typeof process !== 'undefined' && process.env && process.env[name]) {
      return String(process.env[name]).trim();
    }
  } catch (e) {}
  return '';
}

function workflowName() {
  try {
    if (typeof $workflow !== 'undefined' && $workflow && $workflow.name) {
      return String($workflow.name).trim();
    }
  } catch (e) {}
  return '';
}

function isDevWorkflow() {
  return /^DEV\s*-/i.test(workflowName());
}

function envFor(name) {
  if (!isDevWorkflow()) return env(name);
  const map = { CDP_RESULTADOS_SHEETS_URL: 'CDP_DEV_RESULTADOS_SHEETS_URL' };
  const mapped = map[name] || '';
  return mapped ? env(mapped) : env(name);
}

function reportUrl() {
  const configured = envFor('CDP_RESULTADOS_SHEETS_URL');
  if (configured || isDevWorkflow()) return configured;
  return 'https://docs.google.com/spreadsheets/d/1ZBU2d3XVsngOYQH12yU7Mg9DcIzVet2dDmhMtZqHSOo/edit#gid=1185876304';
}

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function durPt(seconds) {
  const s = Math.max(0, Math.round(Number(seconds) || 0));
  if (s >= 3600) {
    const h = Math.floor(s / 3600);
    const m = Math.floor((s % 3600) / 60);
    return h + 'h' + (m ? ' ' + m + 'min' : '');
  }
  if (s >= 60) return Math.floor(s / 60) + ' min';
  return s > 0 ? s + ' s' : '';
}

function pecaLabel(n) {
  const x = Number(n) || 0;
  return x === 1 ? '1 pe\u00e7a' : x + ' pe\u00e7as';
}

function consultaLine(n) {
  const x = Number(n) || 0;
  if (!x) return 'Resultado consolidado de sites e estoque.';
  return pecaLabel(x) + (x === 1 ? ' consultada em sites e estoque.' : ' consultadas em sites e estoque.');
}

function numberField(summary, key) {
  return Number((summary || {})[key]) || 0;
}

function totalSignals(summary) {
  return (
    numberField(summary, 'with_price') +
    numberField(summary, 'no_price') +
    numberField(summary, 'not_found') +
    numberField(summary, 'blocked') +
    numberField(summary, 'errors')
  );
}

function sectionLines(icon, label, summary) {
  const s = summary || {};
  const lines = [icon + ' *' + label + '*'];
  lines.push('Com pre\u00e7o: *' + numberField(s, 'with_price') + '*');
  if (numberField(s, 'no_price') > 0) lines.push('Sem pre\u00e7o: *' + numberField(s, 'no_price') + '*');
  if (numberField(s, 'not_found') > 0) lines.push('N\u00e3o encontrado: *' + numberField(s, 'not_found') + '*');
  if (numberField(s, 'blocked') > 0) lines.push('Bloqueado: *' + numberField(s, 'blocked') + '*');
  if (numberField(s, 'errors') > 0) lines.push('Erros/timeouts: *' + numberField(s, 'errors') + '*');
  const dur = durPt(s.duration_seconds);
  if (dur) lines.push('Dura\u00e7\u00e3o: ' + dur);
  if (totalSignals(s) === 0) lines.push('Sem resumo registrado.');
  if (String(s.status || '').toLowerCase() === 'failed') {
    lines.push('Status: falha' + (s.failed_reason ? ' - ' + String(s.failed_reason).slice(0, 120) : ''));
  }
  return lines;
}

function sectionHtml(label, summary) {
  const s = summary || {};
  const warning =
    numberField(s, 'blocked') > 0 || numberField(s, 'errors') > 0 || String(s.status || '').toLowerCase() === 'failed';
  return (
    '<div style="border:1px solid #e5e7eb;border-radius:8px;padding:14px 16px;margin:0 0 12px">' +
    '<div style="font-size:13px;color:#111827;font-weight:700;margin-bottom:8px">' +
    escapeHtml(label) +
    '</div>' +
    '<div style="font-size:14px;line-height:1.7;color:#374151">' +
    '<strong>Com pre\u00e7o:</strong> ' +
    numberField(s, 'with_price') +
    '<br><strong>Sem pre\u00e7o:</strong> ' +
    numberField(s, 'no_price') +
    '<br><strong>N\u00e3o encontrado:</strong> ' +
    numberField(s, 'not_found') +
    '<br><strong>Bloqueado:</strong> ' +
    numberField(s, 'blocked') +
    '<br><strong>Erros/timeouts:</strong> ' +
    numberField(s, 'errors') +
    (s.duration_seconds ? '<br><strong>Dura\u00e7\u00e3o:</strong> ' + escapeHtml(durPt(s.duration_seconds)) : '') +
    (warning ? '<br><strong>Status:</strong> conclu\u00eddo com avisos' : '') +
    '</div>' +
    '</div>'
  );
}

const apiResp = $input.first().json;
const claim = apiResp.claim || apiResp.body?.claim || null;
if (!apiResp.ready_for_final || !claim) {
  return [{ json: { skip_send: true, not_ready: true, reason: 'not_ready' } }];
}

const scraper = claim.scraper_summary || {};
const stokapi = claim.stokapi_summary || {};
const url = reportUrl();
const totalSkus = Number(claim.total_skus) || 0;
const consultadaLine = consultaLine(totalSkus);
const totalWithPrice = numberField(scraper, 'with_price') + numberField(stokapi, 'with_price');
const hasWarnings =
  numberField(scraper, 'blocked') +
    numberField(scraper, 'errors') +
    numberField(stokapi, 'blocked') +
    numberField(stokapi, 'errors') >
  0;

let replyChannel = String(claim.reply_channel || '').trim().toLowerCase();
const chatId = String(claim.chat_id || '').trim();
const replyEmail = String(claim.reply_email || '').trim();

if (!replyChannel) {
  if (replyEmail) replyChannel = 'email';
  else if (chatId) replyChannel = 'telegram';
}

if (!chatId && !replyEmail) {
  return [
    {
      json: {
        skip_send: true,
        skipped_no_target: true,
        run_id: claim.run_id,
        sheet_row_numbers: claim.sheet_row_numbers || [],
      },
    },
  ];
}

const tgLines = [
  '\u{1F916} *Assistente CDP*',
  '',
  '\u2705 *Consulta CDP conclu\u00edda*',
  consultadaLine,
  'Resultados com pre\u00e7o: *' + totalWithPrice + '*',
  '',
];
tgLines.push(...sectionLines('\u{1F50E}', WEBSCRAPERS_LABEL, scraper));
tgLines.push('');
tgLines.push(...sectionLines('\u{1F4E6}', ESTOQUE_LABEL, stokapi));
if (url) {
  tgLines.push('');
  tgLines.push('\u{1F4CE} Relat\u00f3rio: ' + url);
}

const htmlSections =
  '<h2 style="margin:0 0 8px;font-size:20px;color:#111827">Consulta CDP conclu\u00edda</h2>' +
  '<p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#475569">' +
  escapeHtml(consultadaLine) +
  '</p>' +
  sectionHtml(WEBSCRAPERS_LABEL, scraper) +
  sectionHtml(ESTOQUE_LABEL, stokapi) +
  (url
    ? '<p style="margin:18px 0 0"><a href="' +
      escapeHtml(url) +
      '" style="display:inline-block;background:#2563eb;color:#fff;text-decoration:none;border-radius:8px;padding:12px 18px;font-weight:700">Abrir relat\u00f3rio</a></p>'
    : '');

const scraperJobIds = Array.isArray(claim.scraper_job_ids) ? claim.scraper_job_ids : [];
const scraperJobId = String(scraperJobIds[0] || '').trim();

return [
  {
    json: {
      skip_send: false,
      run_id: claim.run_id,
      batch_group_id: String(claim.batch_group_id || '').trim(),
      scraper_job_id: scraperJobId,
      scraper_job_ids: scraperJobIds,
      stokapi_job_id: String(claim.stokapi_job_id || '').trim(),
      reply_channel: replyChannel,
      chat_id: chatId,
      email_to: replyEmail,
      sheet_row_numbers: claim.sheet_row_numbers || [],
      msg_telegram: tgLines.join('\n'),
      msg_email_subject: 'Consulta CDP conclu\u00edda - resultado consolidado',
      msg_email_html:
        '<div style="font-family:Arial,sans-serif;color:#1f2937;max-width:640px">' + htmlSections + '</div>',
    },
  },
];

// cdp_notifier — trigger sheet NOTIFICADO updates (row numbers from final formatter).

const prep = $('📣 Formatar mensagem final').first().json;
const rows = Array.isArray(prep.sheet_row_numbers) ? prep.sheet_row_numbers : [];
const status = prep.skipped_no_target ? '🚫 Sem destino' : '✅ Notificado';

if (!rows.length) {
  return [];
}

return [
  {
    json: {
      sheet_row_numbers: rows
        .map((rowNumber) => Number(rowNumber))
        .filter((n) => Number.isFinite(n) && n > 0),
      NOTIFICADO: status,
    },
  },
];

// cdp_notifier — merge NOTIFICADO status onto sheet rows (preserve row_number lineage).

const trigger = $('🔧 Expandir NOTIFICADO').first().json || {};
const status = trigger.NOTIFICADO || '✅ Notificado';
const marksByRow = {};
for (const rn of trigger.sheet_row_numbers || []) {
  const n = Number(rn);
  if (Number.isFinite(n) && n > 0) marksByRow[n] = status;
}

const items = $input.all();
const out = [];
for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const row = item.json || {};
  const rn = row.row_number;
  if (marksByRow[rn] === undefined) continue;
  out.push({
    json: {
      ...row,
      NOTIFICADO: marksByRow[rn],
    },
    pairedItem: item.pairedItem ?? { item: i },
  });
}
return out;

// cdp_notifier — build job-scoped UTF-8 CSV for aggregate final email attachment.

function numericPrice(value) {
  if (value === null || value === undefined || value === '') return null;
  const n = Number(value);
  return Number.isFinite(n) && n > 0 ? n : null;
}

function partHasValidPrice(part) {
  return !!(part && part.exact_match && numericPrice(part.price) !== null);
}

function siteParts(site) {
  if (Array.isArray(site?.results)) return site.results;
  if (Array.isArray(site?.parts)) return site.parts;
  return [];
}

function siteHasValidPrice(site) {
  if (site?.has_valid_price === true || String(site?.sku_result || '').toUpperCase() === 'FOUND_PRICE') {
    return true;
  }
  return siteParts(site).some(partHasValidPrice);
}

function siteHasExactEvidence(site) {
  if (String(site?.sku_result || '').toUpperCase() === 'NO_PRICE') return true;
  if (String(site?.status || '').toLowerCase() === 'no_price') return true;
  return siteParts(site).some((part) => !!part?.exact_match);
}

function skuHasValidPrice(row) {
  if (row?.has_valid_price === true || String(row?.sku_result || '').toUpperCase() === 'FOUND_PRICE') {
    return true;
  }
  const best = row?.best_price || null;
  if (best && best.exact_match !== false && numericPrice(best.price) !== null) return true;
  return (Array.isArray(row?.site_results) ? row.site_results : []).some(siteHasValidPrice);
}

function canonicalSkuStatus(row) {
  const explicit = String(row?.sku_result || '').trim().toUpperCase();
  if (explicit) return explicit;
  const sites = Array.isArray(row?.site_results) ? row.site_results : [];
  if (skuHasValidPrice(row)) return 'FOUND_PRICE';
  if (row?.has_any_exact_evidence === true || sites.some(siteHasExactEvidence)) return 'NO_PRICE';
  const statuses = sites.map((site) => String(site?.sku_result || site?.status || '').trim().toUpperCase());
  if (statuses.includes('BLOCKED')) return 'BLOCKED';
  if (statuses.includes('TIMEOUT')) return 'TIMEOUT';
  if (statuses.includes('ERROR')) return 'ERROR';
  return 'NOT_FOUND';
}

function bestExactOffer(skuResult) {
  let bestPrice = null;
  let bestSite = '';
  let bestUrl = '';
  for (const sr of skuResult.site_results || []) {
    for (const part of sr.results || []) {
      if (!partHasValidPrice(part)) continue;
      const price = numericPrice(part.price);
      if (bestPrice === null || price < bestPrice) {
        bestPrice = price;
        bestSite = sr.site_name || sr.site || '';
        bestUrl = part.product_url || '';
      }
    }
  }
  return { bestPrice, bestSite, bestUrl };
}

function statusLabel(status) {
  if (status === 'FOUND_PRICE') return 'Encontrado';
  if (status === 'NO_PRICE') return 'Sem preco';
  if (status === 'BLOCKED') return 'Bloqueado';
  if (status === 'TIMEOUT' || status === 'ERROR') return 'Erro';
  return 'Sem resultado';
}

function csvEscape(val) {
  const s = String(val ?? '');
  if (/[;\r\n"]/.test(s)) return '"' + s.replace(/"/g, '""') + '"';
  return s;
}

const fmt = $('📣 Formatar mensagem final').first().json;
const jobPayload = $input.first().json;
const results = Array.isArray(jobPayload.results) ? jobPayload.results : [];
const batchGroupId = String(fmt.batch_group_id || 'job').trim();
const jobId = String(jobPayload.job_id || fmt.scraper_job_id || 'unknown').trim();
const dateStamp = new Date().toISOString().slice(0, 10);

const rows = [];
for (const skuResult of results) {
  const sku = skuResult.sku || '';
  const canonical = canonicalSkuStatus(skuResult);
  const offer = canonical === 'FOUND_PRICE' ? bestExactOffer(skuResult) : { bestPrice: null, bestSite: '', bestUrl: '' };
  const siteSummary = [];
  for (const sr of skuResult.site_results || []) {
    const siteName = sr.site_name || sr.site || '';
    const srStatus = String(sr.sku_result || sr.status || '').toLowerCase() || 'sem_resultado';
    siteSummary.push(siteName + (siteHasValidPrice(sr) ? ' OK' : ' ' + srStatus));
  }
  rows.push({
    SKU: sku,
    STATUS: statusLabel(canonical),
    'MELHOR PREÇO':
      offer.bestPrice !== null
        ? 'BRL ' + Number(offer.bestPrice).toLocaleString('pt-BR', { minimumFractionDigits: 2 })
        : 'N/A',
    SITE: offer.bestSite || 'N/A',
    LINK: offer.bestUrl || 'N/A',
    'SITES CHECADOS': siteSummary.join(' | '),
    DATA: new Date().toLocaleDateString('pt-BR'),
  });
}

const header = ['SKU', 'STATUS', 'MELHOR PREÇO', 'SITE', 'LINK', 'SITES CHECADOS', 'DATA'];
const csvLines = [header.map(csvEscape).join(';')];
for (const row of rows) {
  csvLines.push(header.map((h) => csvEscape(row[h] ?? '')).join(';'));
}
const csvText = '\ufeff' + csvLines.join('\r\n');
const b64 = Buffer.from(csvText, 'utf8').toString('base64');
const fname = `cdp_${batchGroupId}_${dateStamp}.csv`;

return [
  {
    json: {
      ...fmt,
      csv_filename: fname,
      csv_row_count: rows.length,
    },
    binary: {
      data: {
        data: b64,
        mimeType: 'text/csv; charset=utf-8',
        fileName: fname,
        fileExtension: 'csv',
      },
    },
  },
];
